={{
  (() => {
    const texto = $node["Telegram Trigger"].json.message.text;
    const menuPrincipal = {
      '0': 'Menú / Ayuda',
      '1': 'Menú / Crear Solicitud',
      '2': 'Menú / Consultar Estado',
      '3': 'Menú / Mis Solicitudes',
      '4': 'Menú / Reportes',
      '5': 'Menú / Configuración',
      '9': 'Menú / Volver al Inicio',
      '/start': 'Inicio / Bienvenida'
    };

    // 1. Si es un número del menú principal o /start
    if (menuPrincipal[texto]) {
      return menuPrincipal[texto];
    }

    // 2. Si no es un número del menú, revisar en qué estado está el usuario
    if ($node["opciones"]?.activeRule !== undefined) {
      const nombresOpciones = ['Ayuda', 'Crear', 'Consultar', 'Mis Solicitudes', 'Reportes', 'Configuración'];
      return `Procesando: ${nombresOpciones[$node["opciones"].activeRule] || 'Opción Desconocida'}`;
    }

    if ($node["estado"]?.activeRule !== undefined) {
      const nombresEstados = ['Prioridad', 'Descripción', 'Estado 2', 'Estado 3', 'Estado 4'];
      return `Flujo: ${nombresEstados[$node["estado"].activeRule] || 'Procesando Datos'}`;
    }

    return 'Inicio / Entrada de Texto';
  })()
}}

parameters.jsCode:
let mensaje = "📋 **Tus últimas 5 Solicitudes:**\n\n";

const tickets = $input.all().reverse();

if (tickets.length === 0) {
    return { mensaje_final: "No tienes tickets registrados actualmente. ❌" };
}


const ultimosCinco = tickets.slice(0, 5);

ultimosCinco.forEach((ticket) => {
    const id = String(ticket.json.id_ticket || "Sin ID");
    const desc = String(ticket.json.descripcion || "Sin descripción");

    mensaje += `🎫 **ID:** \`${id}\`\n`;
    mensaje += `📝 **Resumen:** ${desc.substring(0, 40)}...\n`;
    mensaje += `--------------------------\n`;
});

mensaje += "\n✍️ **Escribe el ID del ticket que deseas consultar.**";

return { mensaje_final: mensaje };

